#include <iostream>

int main() {
    int n;
    std::cin >> n;
    int sign = n < 0 ? -1 : 1;
    n = n * sign;
    int reversed = 0;
    while (n > 0) {
        reversed = reversed * 10 + n % 10;
        n /= 10;
    }
    std::cout << reversed * sign << std::endl;
    return 0;
}
